const database = "/data/vault.duckdb";
const url = "http://duckdb-service:8001/query";
const sql = "SELECT table_schema, table_name, table_type FROM information_schema.tables ORDER BY table_schema, table_name";

try {
  const res = await this.helpers.httpRequest({
    method: "POST",
    url,
    headers: { "Content-Type": "application/json" },
    body: { sql, database },
    json: true
  });
  const rows = res.rows || [];
  const grouped = {};
  for (const row of rows) {
    const schema = row.table_schema || "main";
    if (!grouped[schema]) grouped[schema] = [];
    grouped[schema].push(row.table_name);
  }
  return JSON.stringify({ database, schemas: grouped }, null, 2);
} catch (e) {
  return JSON.stringify({ error: e.message, database });
}
